#include <stdio.h>
#include <string.h>

int gcd(int a, int b) {
    while (b) {
        int t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; char S[100005];
        scanf("%d %s", &N, S);
        int freq[256] = {0};
        for (int i = 0; i < N; ++i) freq[(unsigned char)S[i]]++;
        int g = 0;
        for (int i = 0; i < 256; ++i) if (freq[i]) {
            if (g == 0) g = freq[i];
            else g = gcd(g, freq[i]);
        }
        printf("%d\n", g);
    }
    return 0;
}

