import sys, math

def main():
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        S = next(it)
        freq = [0]*256
        for ch in S:
            freq[ord(ch)] += 1
        g = 0
        for f in freq:
            if f:
                g = f if g == 0 else math.gcd(g, f)
        out.append(str(g))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

